// AGENTE 2 (parte 1) - Normalizar vagas das 3 fontes + remover duplicadas
// Este node roda 1x recebendo os 3 resultados brutos (RemoteOK, Remotive, Arbeitnow)
// que chegaram juntos pelos nodes de Merge.

const rawItems = $input.all();

// IDs já salvos no Notion (para não duplicar)
let idsExistentes = [];
try {
  const notionResp = $('Buscar Vagas já salvas no Notion').first().json;
  idsExistentes = (notionResp.results || []).map(page => {
    const prop = page.properties && page.properties['ID Externo'];
    return (prop && prop.rich_text && prop.rich_text[0] && prop.rich_text[0].plain_text) || '';
  }).filter(Boolean);
} catch (e) {
  idsExistentes = [];
}

const vagas = [];

for (const item of rawItems) {
  const body = item.json;

  // --- RemoteOK: array direto, primeiro item costuma ser aviso legal ---
  if (Array.isArray(body)) {
    for (const job of body) {
      if (!job.id || !job.position) continue;
      vagas.push({
        id_externo: 'remoteok_' + job.id,
        titulo: job.position,
        empresa: job.company || 'Não informado',
        local: job.location || 'Remoto',
        remoto: true,
        link: job.url || ('https://remoteok.com/remote-jobs/' + job.id),
        descricao: String(job.description || '').replace(/<[^>]+>/g, ' ').slice(0, 4000),
        tags: job.tags || [],
        fonte: 'RemoteOK'
      });
    }
  }

  // --- Remotive: { jobs: [...] } ---
  if (body && Array.isArray(body.jobs)) {
    for (const job of body.jobs) {
      vagas.push({
        id_externo: 'remotive_' + job.id,
        titulo: job.title,
        empresa: job.company_name || 'Não informado',
        local: job.candidate_required_location || 'Remoto',
        remoto: true,
        link: job.url,
        descricao: String(job.description || '').replace(/<[^>]+>/g, ' ').slice(0, 4000),
        tags: job.tags || [],
        fonte: 'Remotive'
      });
    }
  }

  // --- Arbeitnow: { data: [...] } ---
  if (body && Array.isArray(body.data)) {
    for (const job of body.data) {
      vagas.push({
        id_externo: 'arbeitnow_' + job.slug,
        titulo: job.title,
        empresa: job.company_name || 'Não informado',
        local: job.location || 'Remoto',
        remoto: !!job.remote,
        link: job.url,
        descricao: String(job.description || '').replace(/<[^>]+>/g, ' ').slice(0, 4000),
        tags: job.tags || [],
        fonte: 'Arbeitnow'
      });
    }
  }
}

// Remove duplicadas dentro da própria execução e vagas já salvas no Notion
const vistas = new Set();
const novas = vagas.filter(v => {
  if (idsExistentes.includes(v.id_externo)) return false;
  if (vistas.has(v.id_externo)) return false;
  vistas.add(v.id_externo);
  return true;
});

return novas.map(v => ({ json: v }));

