// Extrai o JSON retornado pela OpenAI (vem dentro de choices[0].message.content)
const resp = $input.first().json;
let texto = '';
try {
  texto = resp.choices[0].message.content;
} catch (e) {
  texto = '{}';
}

// Remove possíveis cercas de markdown, por segurança (response_format json_object já evita isso, mas não custa manter)
texto = texto.replace(/```json/g, '').replace(/```/g, '').trim();

let avaliacao;
try {
  avaliacao = JSON.parse(texto);
} catch (e) {
  avaliacao = {
    compatibilidade: 0,
    pontos_fortes: [],
    gaps: ['Erro ao interpretar resposta da IA'],
    vale_a_pena: false,
    resumo_empresa: '',
    senioridade_da_vaga: 'Nao especificado',
    tecnologias_encontradas: []
  };
}

const vaga = $('Processar Uma Vaga por Vez').item.json;

return [{
  json: {
    ...vaga,
    ...avaliacao
  }
}];

